:root {
  --card-bg: #ffffff;
  --card-border: #e2e8f0;
  --header-bg: #1e293b;
  --tag-bg: #0ea5e9;
  --tag-text: #ffffff;
  --product-name-color: #ffffff;
  --product-model-color: #94a3b8;
  --score-number-color: #38bdf8;
  --score-label-color: #94a3b8;
  --label-color: #475569;
  --bar-track-bg: #e2e8f0;
  --bar-fill-color: #0ea5e9;
  --value-color: #1e293b;
  --positive-color: #16a34a;
  --positive-bg: #dcfce7;
  --negative-color: #dc2626;
  --negative-bg: #fee2e2;
  --vote-desc-color: #64748b;
  --review-count-color: #64748b;
  --btn-bg: #1e293b;
  --btn-text: #ffffff;
  --btn-border: #334155;
}

.review-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 16px;
  overflow: hidden;
  width: 500px;
  max-width: 100%;
}

.review-header {
  background: var(--header-bg);
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.product-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.product-tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  padding: 2px 8px;
  border-radius: 4px;
  align-self: flex-start;
}

.product-name {
  color: var(--product-name-color);
  font-size: 18px;
  font-weight: 700;
  margin: 0;
  line-height: 1.2;
}

.product-model {
  color: var(--product-model-color);
  font-size: 12px;
  margin: 0;
}

.overall-score {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex-shrink: 0;
}

.score-number {
  color: var(--score-number-color);
  font-size: 36px;
  font-weight: 800;
  line-height: 1;
}

.score-label {
  color: var(--score-label-color);
  font-size: 11px;
  white-space: nowrap;
}

.rating-breakdown {
  padding: 16px 20px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  border-bottom: 1px solid var(--card-border);
}

.rating-row {
  display: flex;
  align-items: center;
  gap: 10px;
}

.rating-label {
  color: var(--label-color);
  font-size: 13px;
  font-weight: 500;
  width: 100px;
  flex-shrink: 0;
}

.rating-bar-track {
  flex: 1;
  height: 8px;
  background: var(--bar-track-bg);
  border-radius: 99px;
  overflow: hidden;
}

.rating-bar-fill {
  height: 100%;
  background: var(--bar-fill-color);
  border-radius: 99px;
}

.rating-value {
  color: var(--value-color);
  font-size: 13px;
  font-weight: 700;
  width: 28px;
  text-align: right;
  flex-shrink: 0;
}

.review-footer {
  padding: 12px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.vote-counts {
  display: flex;
  gap: 8px;
}

.vote-item {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 5px 10px;
  border-radius: 8px;
  font-size: 12px;
}

.vote-positive {
  background: var(--positive-bg);
  color: var(--positive-color);
}

.vote-negative {
  background: var(--negative-bg);
  color: var(--negative-color);
}

.vote-icon {
  font-size: 10px;
}

.vote-num {
  font-weight: 700;
}

.vote-desc {
  color: var(--vote-desc-color);
}

.vote-positive .vote-desc,
.vote-negative .vote-desc {
  color: inherit;
  opacity: 0.75;
}

.review-meta {
  display: flex;
  align-items: center;
  gap: 12px;
}

.review-count {
  color: var(--review-count-color);
  font-size: 12px;
}

.write-review-btn {
  background: var(--btn-bg);
  color: var(--btn-text);
  border: 1px solid var(--btn-border);
  border-radius: 8px;
  padding: 7px 14px;
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
}
